const Q_GEOGRAPHY_2004=[{"id": "objective>Geography>2004>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The height of the point marked X is approximately </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">572m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">582m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">592m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">562m </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate height, look at the closest contour line and get its heigh value. Use intuition to calculate unlabelled contour based on the contour lines height differences.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2004>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> All the settlement are located </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">on top of the hills </div>", "<div style=\"font-family:Cambria;font-size:17px;\">away from the floodplains </div>", "<div style=\"font-family:Cambria;font-size:17px;\">on steep slopes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">on the floodplains </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Typical rural settlements located on hill tops for security & survival from flooding.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2004>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Gross capital firmation occurred between </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">southeast </div>", "<div style=\"font-family:Cambria;font-size:17px;\">southwest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">northeast </div>", "<div style=\"font-family:Cambria;font-size:17px;\">northwest</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Southwest seems to have the network of major roads & settlements </div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2004>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The only two likely occupations in the area are fishing and </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lumbering </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">farming </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Farming: There are lots of scattered cultivation on the map thus deducing  farming as a major occupation here.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2004>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the map below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The distance by road from Zara to Lime is approximately </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4km </div>", "<div style=\"font-family:Cambria;font-size:17px;\">6km </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10km </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8km </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Distance = measured distance in car from white thread read on metre rule   <br/>  1cm : 100,000cm  <br/>  1cm : 1km  <br/>  multiplied by scale.  <br/>  = 6cm  <br/>  = 6 × 1km = 6km  <br/>  or <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">6 × 100,000<hr size=\"1\" />100,000</td></tr></table></div>  <br/>  = 6km</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2004>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The gross capital formation from 1966 was </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N1500million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N1200million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N900 million </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N150million </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Add up gross capital formation between years of interest (1964 - 1966)  <br/>  = 400 + 600 + 500  <br/>  = ₦1,500 million. </div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2004>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The histogram shows that a steady growth of gross capital formation occurred between </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1967 and 1971 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1964 and 1968 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1969 and 1973 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1966 and 1970 </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Between 1969 & 1973  <br/> There was increase of 400 to 500 to 700 to 1000 to 1200 million.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2004>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which is simplest method of rapid distance measurement in surveying? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pacing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tape measurement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chaining </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Compass measurement </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For straight line measurements, the tape measurement is the simplest once the start & end pegs have been set.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2004>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> Express the agriculture production of Y in degrees </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">57<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">67<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">37<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">47<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Y = 18.6% = 0.186  <br/> ∴ % of Y in 360<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>  <br/>  = 0.186 × 360  <br/>  = 67°.</div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2004>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pie chart </div>", "<div style=\"font-family:Cambria;font-size:17px;\">choropleth map </div>", "<div style=\"font-family:Cambria;font-size:17px;\">proportional graph  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bar graph </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Piecharts are water graphical representation of data. </div>", "topic": "PRATICAL GEOGRAPHY I : INTERPRETATION OF STATISTICAL DATA; MAPS AND DIAGRAMS"}, {"id": "objective>Geography>2004>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tin-mining activities in Nigeria are the main causes of environmental degradation on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Western highlands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Eastern highlands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jos Plateau </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Abudu Plateau </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Jos is renowned for its tin-making activities which have degraded the plateau from being undulating to dulating & polluted.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2004>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Niger Delta, the feature that are clearly visible are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">white sandy beaches, tall trees and salt-water swamps </div>", "<div style=\"font-family:Cambria;font-size:17px;\">white sandy beaches, reddish sandy beaches and mangrove trees </div>", "<div style=\"font-family:Cambria;font-size:17px;\">white sandy beaches, tall trees and reddish sandy beaches </div>", "<div style=\"font-family:Cambria;font-size:17px;\">white sandy beaches, salt-water swamps and mangrove trees </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> White sandy beaches are with of fluvial depositions, while salt water swamps & mangroove trees are influenced by the salty Atlantic Ocean.</div>", "topic": "REGIONAL GEOGRAPHY : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2004>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Most of the iron ores produced in Africa are exported because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the producing countries have good transport systems to coastal ports </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the producing countries have low internal consumption capacities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they can only be smelted in modern furnaces that are not locally available </div>", "<div style=\"font-family:Cambria;font-size:17px;\">they are of good quality and in high demand. </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The low internal consumption capacities of African Iron ores producing countries is responsible for the large trend of exportation as our industries are not fully developed to use all these supplies as input for production.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2004>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ECOWAS is comparable to the European Union in terms of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a unified security arrangement </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a common border agreement and policing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the freedom of movement within the community </div>", "<div style=\"font-family:Cambria;font-size:17px;\">uniform currencies besides the local ones. </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ECOWAS just like EU, encourages freedom of movement of member state citizens within the region/West Africa without need for visa.</div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>2004>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oldest system of agriculture in Nigeria which now survives only in very remote areas is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mixed farming </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shifting cultivation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">market gardening </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bush fallowing </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shifting cultivation is an agelong practise which entails moving from one piece of land to another after each farming season to manage soil fertility. </div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2004>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Two examples of inland drainage lakes in Africa are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lake chad and lake-Edwards </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lake Victoria and lake Ngami </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lake chad and lake Turkana </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lake Malawi and Lake turkana </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lake chad & Lake Turkana are both Desert lakes in West Africa & East Africa respectively. <br/> The Lake Turkana drainage basin draws its waters mainly from Kenya Highlands and Ethiopian Highlands. <br/> Chad Basin, Chad also spelled Tchad, vast depression in Central Africa that constitutes the largest inland drainage area on the continent. ... The Chad basin constitutes the largest inland drainage area in Africa</div>", "topic": "REGIONAL GEOGRAPHY : WATER BODIES"}, {"id": "objective>Geography>2004>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest lands in Nigeria are found on the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mambilla Plateau </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oban Hills </div>", "<div style=\"font-family:Cambria;font-size:17px;\">North Central Plateau </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Western Highlands </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mambilla plateau share the highland region at the boundary of Cameroon where the Cameroon mountains are found.</div>", "topic": "REGIONAL GEOGRAPHY : GEOGRAPHICAL REGIONS OF NIGERIA"}, {"id": "objective>Geography>2004>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Unemployment and underemployment are at high levels in West Africa cities because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the people in these cities are lazy </div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is a large youthful population </div>", "<div style=\"font-family:Cambria;font-size:17px;\">many of the city-dwellers are unskilled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrialization is at a slow pace </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In West African cities, industrialization is at a slow pace. This is the reason for unemployment and underemployment.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2004>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The port that handles the highest volume of timber export in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sapele </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Warri </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Port Harcourt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lagos </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Though Sapele was the first port to export timber in Nigeria, Lagos currently handles the largest volume of timber exports in Nigeria.</div>", "topic": "REGIONAL GEOGRAPHY : LUMBERING IN EQUATORIAL AFRICA"}, {"id": "objective>Geography>2004>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Oil production has made much impact on the development of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gabon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Libya </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Algeria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ghana </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Libya is one of the largest oil producers in Africa and the oil industry plays a significant role in its economy.</div>", "topic": "REGIONAL GEOGRAPHY : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2004>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Textile industries in Nigeria are located mostly at  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aba </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oyo </div>", "<div style=\"font-family:Cambria;font-size:17px;\">kaduna </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kano </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kaduna is located in the cotton growing belt of Nigeria thus favouring siting of textile industries there.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2004>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Examples of Africa rivers with deltaic mouths include the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Niger, Nile, Orange and Zambezi </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nile, Zaire, Niger and limpopo </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nile, Niger, Senegal and Volta </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zambezi, Nile, volta and Niger </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nile delta in Egypt, Volta in Ghana, Niger in Nigeria & Zambezi in Mozambique are all delta with magnificent features in Africa.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2004>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major factor responsible for the low population density in the west coast of Southern Africa is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">slave trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low rainfall </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rugged relief </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disease infestation </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rugged relief (the Namib desert, cape of good hope, etc) is a major factor responsible for low population density in West coast of Southern Africa.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2004>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The proportion of the earth's surface occupied by ocean is approximately </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">87% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">67% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">97% </div>", "<div style=\"font-family:Cambria;font-size:17px;\">77% </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">*Almost* 67% of the earth's surface is covered by oceans. Land mass accounts for about 33%.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2004>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the humid tropical lands, the structure of mature forest is closely related to the demand for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">light </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">food </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sunlight influences the structure of mature forests in humid tropical lands. As it influences large shaped leaves to trap sunlight for photosynthesis, broad overlapping canopies at the top.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2004>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rocks which contain metals in concentrations high enough to be economically profitable to extract and refine are referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">terrestrial resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ores </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ferrous deposits </div>", "<div style=\"font-family:Cambria;font-size:17px;\">minerals </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rocks which contain metals in concentrations high enough to be economically profitable to extract and refine are referred to as ores. An ore is a type of rock that contains sufficient minerals with important elements including metals that can be economically extracted from the rock. The ores are extracted through mining.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2004>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following groups consists of energy resources? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Petroleum, uranium and manganese </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coal, bauxite and uranium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Water, copper and sun </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Coal, petroleum and water </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coal, petroleum & water can all be used to generate energy based on commercial availability & affordability.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL RESOURCES"}, {"id": "objective>Geography>2004>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Spruce, fir and pine are trees found in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mediterranean woodlands </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monsoon forests </div>", "<div style=\"font-family:Cambria;font-size:17px;\">coniferous forest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropical rainforest </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Spruce, fir, and pine are all types of trees that are typically found in coniferous forests. Coniferous forests are characterized by cone-bearing trees with needles rather than leaves. These types of trees are well adapted to survive in cold and temperate climates, which is where coniferous forests are typically found.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2004>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these hazards would most likely result directly from deforestation? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water pollution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Soil erosion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mass wasting </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Drought </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Other hazards stated are indirectly linked to deforestation. However, soil erosion is a direct result of deforestation as tree leaves & stem are no more available to low down & store rainwater while roots to slow down flood water & liquid oil are removed.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2004>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mass of air whose isobars form a circular shape, with low pressure in the centre and increasing towards the outside, is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hurricane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">typhoon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">harmattan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclone </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The low pressure in the centre is referred to as the eye of the storm. This is a peculiar characteristics of hurricane.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2004>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process by which organic matter is decomposed and synthesized to form part of the soil is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">humification  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mineralization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">laterization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrification </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Humification is the process by which organic matter is decomposed and synthesized to form part of the soil. It involves the transformation of biological material into a substance known as humus, a dark, stable form of organic matter that is resistant to further decomposition.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2004>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> What pattern of flow did the river develop towards the southern edge of the mapped area? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">meandering </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Straight </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Braiding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Raial </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Braiding is the splitting of a water body into different lines as it flows down its river course-classically most spectacular forms of braiding are at river delta or at the source in impervious rock formation where water finds the path of least resistance to flow.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2004>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In what stage of development is the river? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">late youth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Old age </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Early youth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Maturity age </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Old stage because lots of alluvial deposits are being observed, meaning low river velocity & high load volume of sediments with meander & braiding occurring.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2004>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an ecosystem, bacteria and some other microscopic organism are best described as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">secondary consumers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">major decomposers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary decomposers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary consumers </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria & some other microscopic organisms form the 1st layer of action on decomposing organic matter or humification, thus referred to as primary decomposers. Shelf fungus is a fungus that grows on the sides of trees. It grows into the tree and decomposes it slowly.Two primary decomposers are fungi and bacteria. Their function in the recycling of life materials is very prominent because without them all organisms that died would decompose slowly.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL INTERACTION"}, {"id": "objective>Geography>2004>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The process whereby water changes from liquid to gaseous state is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">freezing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">condensation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Evaporation is the process by which liquid changes to gaseous form  <br/>  Freezing = Liquid to solid  <br/> Condensation = gaseous to liquid  <br/>  Sublimation = Solid to gas</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2004>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A serious environmental hazard which causes both vertical and lateral displacement of parts of the earth's crust is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">earthquake </div>", "<div style=\"font-family:Cambria;font-size:17px;\">volcano </div>", "<div style=\"font-family:Cambria;font-size:17px;\">landslide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">weathering </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An earthquake is a sudden and violent shaking of the ground, often caused by movement of the Earth's tectonic plates. This movement can cause both vertical and lateral displacement of parts of the Earth's crust. Volcanoes, landslides, and weathering do not typically cause both types of displacement.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2004>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the standard time of a country is GMT + 1hr, which longitude's local time is adopted by the country? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>E</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>W </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">0</span>E </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Standard time is the local time at a country's standard meridian. This is usually based on the local time at a longitude that is a multiple of 15 degrees. If a country's standard time is GMT + 1 hour, it means that the country's standard meridian is 15 degrees to the east of the Prime Meridian (0 degrees longitude). Therefore, the correct answer is 15 degrees East.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2004>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Migrant-receiving areas tend to be characterized by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equal sex ratio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high per capital income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the predominance of males </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extensive industrial development </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Migrant-receiving areas are often characterized by extensive industrial development. This is because these areas often offer more job opportunities, which attract migrants. The other options, such as equal sex ratio, high per capita income, and the predominance of males, can vary depending on the specific circumstances of the migrant-receiving area.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2004>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The settlement pattern associated with pastoral farming is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">radial </div>", "<div style=\"font-family:Cambria;font-size:17px;\">disperse </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pastoral farming like those found with fulani herdsmen are usually dispersed settlements. Having scattered individual families far apart in order to have adequate pasture for their herd of cattles.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2004>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Air transportation is poorly developed in the Third World because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">poor economic base </div>", "<div style=\"font-family:Cambria;font-size:17px;\">few indigenous airline operators </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ill-equipped airports </div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor technology </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A thriving economy will support all other options stated & thus eliminate these as negatives & boost the air transport industry in 3rd world countries.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2004>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Squatter settlement are indicative of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the dominance of small families </div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor urban planning </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shortage of building materials </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the great pressure on available housing </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When demand exceeds supply of decent housing with increasing low income settler migration, squatter settlements are bound to occur in urban centres.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2004>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The invisible component of international trade consist of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">precious metals and fuels </div>", "<div style=\"font-family:Cambria;font-size:17px;\">processed foods and textiles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">financial services and tourism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">raw materials and machinery </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Financial services & tourism are intangible components of high order international trade in services.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2004>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A modern method of animal rearing in which pasture is grown for the animals is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pastoralism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">free range </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transhumance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ranching </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ranching is the modern method of cattle rearing with special fodder grown for cattle on large expanse of land where cattles are lodged e.g Obudu Cattle Ranch.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2004>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The human factor that contributes to the population growth of an area is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">death rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">industrialization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">afforestation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">immigration </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Industrialization is a human factor that contributes to the population growth of an area.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2004>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Tourism is an example of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">quaternary activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary activities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary activities </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Tourism is an example of tertiary activities. Tertiary activities involve the provision of services to businesses as well as final consumers. Services may involve the transport, distribution and sale of goods from producer to a consumer, as in retailing, or may involve the provision of a service, such as in tourism.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2004>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The areal expansion of town leads to the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">development of wide streets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">takeover of agricultural land  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">collapse of central markets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">emergence of business centres </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Areal expansion of town leads to development of suburbs at the urban fringes taking over agricultural lands. </div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2004>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The country that relies heavily on imported raw materials for her industrial development is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The United States of America </div>", "<div style=\"font-family:Cambria;font-size:17px;\">France </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The United Kingdom </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Japan </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Japan lacks natural resources and her industrialization is hinged on raw material import from all over the world.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2004>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Trade in ivory has declined in recent years because of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stringent international control </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marked decrease in world demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the development of synthetic substitutes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marked decrease in the population of elephants  </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">More strict international collaborations to control trade in poached elephant tusks have yielded results globally.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2004>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rapid rate of population growth in developing countries has led to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high international emigration </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the pressure on available resources </div>", "<div style=\"font-family:Cambria;font-size:17px;\">rapid economical development </div>", "<div style=\"font-family:Cambria;font-size:17px;\">overpopulation </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Due to increased population pressures in developing countries, desperate  citizens coupled with harsh environmental condition have led to an increased trend in both legal & illegal international emigration.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2004>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest category of rural settlement is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">village </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hamlet </div>", "<div style=\"font-family:Cambria;font-size:17px;\">homestead </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hut </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Village is the highest hierarchy of rural settlement  <br/>  hut → homestead → hamlet → village.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}];
